    // Master list — ordered, for browsing
    private List<Product> allProducts = new ArrayList<>();

    // Lookup by SKU — O(1)
    private Map<String, Product> bySku = new HashMap<>();

    // Grouping by category
    private Map<String, List<Product>> byCategory = new HashMap<>();

    // Low-stock alerts — unique SKUs with stock < threshold
