public List<String> removeDiscontinued() {
    List<String> removed = new ArrayList<>();
    Iterator<Product> it = allProducts.iterator();
    while (it.hasNext()) {
        Product p = it.next();
        if (p.isDiscontinued()) {
            removed.add(p.getSku() + ":" + p.getName());
            it.remove();
            bySku.remove(p.getSku());  // keep all structures in sync!
            lowStockSkus.remove(p.getSku());
            // Note: byCategory and byPrice cleanup left as exercise
        }
    }
    return removed;
}
